  create policy "Users can delete own readings"
  on "public"."bible_reading"
  as permissive
  for delete
  to public
using ((auth.uid() = user_id));



  create policy "Users can insert own readings"
  on "public"."bible_reading"
  as permissive
  for insert
  to public
with check ((auth.uid() = user_id));



  create policy "Users can read own readings"
  on "public"."bible_reading"
  as permissive
  for select
  to public
using ((auth.uid() = user_id));



  create policy "Users can only manage their own fitness entries"
  on "public"."fitness"
  as permissive
  for all
  to public
using ((auth.uid() = user_id))
with check ((auth.uid() = user_id));



  create policy "Users can only manage their own goals"
  on "public"."goals"
  as permissive
  for all
  to public
using ((auth.uid() = user_id))
with check ((auth.uid() = user_id));



  create policy "Users can only manage their own journal entries"
  on "public"."journal"
  as permissive
  for all
  to public
using ((auth.uid() = user_id))
with check ((auth.uid() = user_id));



  create policy "Users can only insert their own summaries"
  on "public"."monthly_summaries"
  as permissive
  for insert
  to public
with check ((auth.uid() = user_id));



  create policy "Users can only read their own summaries"
  on "public"."monthly_summaries"
  as permissive
  for select
  to public
using ((auth.uid() = user_id));



  create policy "Users can only manage their own prayers"
  on "public"."prayer_log"
  as permissive
  for all
  to public
using ((auth.uid() = user_id))
with check ((auth.uid() = user_id));



  create policy "Users can insert own profile"
  on "public"."profiles"
  as permissive
  for insert
  to public
with check ((auth.uid() = id));



  create policy "Users can read own profile"
  on "public"."profiles"
  as permissive
  for select
  to public
using ((auth.uid() = id));



  create policy "Users can update own profile"
  on "public"."profiles"
  as permissive
  for update
  to public
using ((auth.uid() = id))
with check ((auth.uid() = id));



  create policy "Public can read verses"
  on "public"."verses"
  as permissive
  for select
  to public
using (true);


CREATE TRIGGER on_auth_user_created AFTER INSERT ON auth.users FOR EACH ROW EXECUTE FUNCTION public.handle_new_user();


